class Solution:
    def longestSubstring(self, s, k):
        n = len(s)
        best = 0
        # brute force over all substrings
        for i in range(n):
            count = {}
            for j in range(i, n):
                count[s[j]] = count.get(s[j], 0) + 1
                if all(v >= k for v in count.values()):
                    best = max(best, j - i + 1)
        return best

