class Solution:
    def longestSubstring(self, s, k):
        from collections import Counter
        def helper(sub):
            if len(sub) < k:
                return 0
            counts = Counter(sub)
            for ch, c in counts.items():
                if c < k:
                    return max(helper(part) for part in sub.split(ch))
            return len(sub)
        return helper(s)

