var longestSubstring = function(s, k) {
    const helper = (sub) => {
        if (sub.length < k) return 0;
        const counts = {};
        for (const ch of sub) counts[ch] = (counts[ch] || 0) + 1;
        for (const ch in counts) {
            if (counts[ch] < k) {
                let best = 0;
                for (const part of sub.split(ch)) best = Math.max(best, helper(part));
                return best;
            }
        }
        return sub.length;
    };
    return helper(s);
};
